  ('elementary-f29af906-moex-00299', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '下列何種限制登記，不屬經由法院或行政執行分署囑託登記機關辦理之登記？', '["查封", "預告登記", "假處分", "破產登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00300', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地登記規則規定，有關區分所有建物之登記，下列敘述何者錯誤？', '["區分所有權人得就其專有部分及所屬共有部分之權利，單獨申請建物所有權第一次登記", "所屬共有部分，除法規另有規定外，依區分所有權人按其設置目的及使用性質之約定情形，分別合 併，另編建號，單獨登記為各相關區分所有權人共有", "共有部分之登記僅建立標示部及加附區分所有建物共有部分附表", "共有部分之登記，得依申請發給所有權狀"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00301', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地登記規則規定，有關土地權利信託登記，下列敘述何者錯誤？', '["信託以契約為之者，信託登記應由委託人與受託人會同申請之", "信託以遺囑為之者，信託登記應由繼承人辦理繼承登記後，會同受託人申請之", "信託以遺囑為之者，如遺囑另指定遺囑執行人時，應於辦畢遺囑執行人及繼承登記後，由遺囑執行 人會同受託人申請之", "信託以遺囑為之者，於繼承人有無不明時，應於辦畢遺產管理人登記後，由遺產管理人單獨申請之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00302', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地登記規則規定，土地經辦理破產登記後，未為塗銷前，登記機關應停止下列何項之新登記？', '["公同共有繼承登記", "贈與登記", "照價收買之登記", "徵收之登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00303', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '大陸地區人民因住宅用途申請取得臺灣地區不動產物權案件經內政部許可，許可文件之有效期限最 長多久？', '["6個月", "1年", "2年", "3年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00304', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '有關土地複丈申請人，下列之敘述何者錯誤？', '["共有土地之協議分割、合併，由其中一名共有人代表申請", "依民法第769條規定因時效完成所為之登記請求者，由權利人申請", "因建造行為鑑界，得由建造執照起造人會同土地所有權人或管理人申請", "因承租土地經界不明，由承租人會同土地所有權人或管理人申請"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
